#@title 🔒 **EXAM MODE ACTIVATED** — Do not modify this cell { display-mode: "form" }
#@markdown > This cell activates secure exam restrictions. **Do not delete or modify it.**

import builtins as _b
from IPython.display import display, HTML as _HTML

# --- Block dangerous + AI modules ---
_orig_import = _b.__import__
_BLOCKED = {
    'subprocess','shutil','pathlib','signal','ctypes','importlib',
    'openai','anthropic','google.generativeai','genai',
    'langchain','langchain_core','langchain_openai',
    'transformers','huggingface_hub','cohere','replicate',
    'bard','gemini','chatgpt'
}
def _safe_import(name, *args, **kwargs):
    if name in _BLOCKED or any(name.startswith(b+'.') for b in _BLOCKED):
        raise ImportError(f'⛔ Module "{name}" is blocked during exam mode. AI tools are not permitted.')
    return _orig_import(name, *args, **kwargs)
_b.__import__ = _safe_import

# --- Block shell commands (!, %system, %sx) ---
from IPython import get_ipython as _gi
_ip = _gi()
if _ip:
    _ip.system = lambda *a, **k: print('⛔ Shell commands are disabled during exam mode.')

# --- Show exam mode banner + tab detection + disable Colab AI ---
display(_HTML('''
<div style="background:linear-gradient(135deg,#312e81,#1e1b4b);padding:16px 24px;border-radius:12px;border:1px solid rgba(99,102,241,0.3);margin-bottom:8px">
  <div style="display:flex;align-items:center;gap:12px">
    <span style="font-size:24px">🔒</span>
    <div>
      <div style="color:#e0e7ff;font-weight:700;font-size:15px">Exam Mode Active</div>
      <div style="color:#a5b4fc;font-size:13px">AI tools, shell commands, and restricted modules are disabled.</div>
    </div>
    <div id="_tab_warn" style="margin-left:auto;display:none;background:#ef4444;color:white;padding:4px 12px;border-radius:6px;font-size:12px;font-weight:600">⚠️ Tab switches: <span id="_tab_count">0</span></div>
  </div>
</div>
<script>
// --- Warn on close/navigate ---
window.addEventListener("beforeunload", function(e) {
  e.preventDefault();
  e.returnValue = "You have an active exam. Are you sure you want to leave?";
  return e.returnValue;
});

// --- Detect tab switching ---
var _tabSwitches = 0;
document.addEventListener("visibilitychange", function() {
  if (document.hidden) {
    _tabSwitches++;
    var el = document.getElementById("_tab_count");
    var warn = document.getElementById("_tab_warn");
    if (el) el.textContent = _tabSwitches;
    if (warn) warn.style.display = "block";
    console.warn("⚠️ Tab switch detected! Count: " + _tabSwitches);
  }
});

// --- Disable Colab AI sidebar + hide cell controls + hide Gemini ---
setTimeout(function() {
  var style = document.createElement('style');
  style.textContent = `
    /* Hide Gemini AI button */
    colab-ai-button, .colab-ai-button,
    [data-p="AI"], .colab-ai-sidebar, #colab-ai-button,
    colab-recitation-button,
    .gemini-button, [aria-label*="Gemini"],
    [aria-label*="AI"], [aria-label*="assistant"],
    .gm-fab, .gm-floating-button,
    div[style*="border-radius: 50%"][style*="background"][style*="position: fixed"],
    .colab-bottom-fab-container,
    [class*="colab-ai"], [id*="colab-ai"],
    .fab-container { display: none !important; visibility: hidden !important; }
    /* Hide cell toolbar actions */
    .cell-toolbar .cell-toolbar-actions { display: none !important; }
    .add-cell { display: none !important; }
    button[aria-label="Move cell up"],
    button[aria-label="Move cell down"],
    button[aria-label="Delete cell"],
    button[aria-label="More cell actions"],
    button[aria-label="Link to cell"] { display: none !important; }
    .cell-execution-container .buttonbar { pointer-events: auto !important; }
  `;
  document.head.appendChild(style);
  // Also try to remove the element directly
  document.querySelectorAll('colab-ai-button, .gm-fab, [class*="colab-ai"]').forEach(function(el) { el.remove(); });
}, 2000);
</script>
'''))

number=50
for i in range(1,number+1):
  print(i)
